class Solution:
    def findKOr(self, nums, k):
        rows = [bin(x)[2:].zfill(32)[::-1] for x in nums]
        result = 0
        for i, col in enumerate(zip(*rows)):
            if col.count('1') >= k:
                result |= (1 << i)
        return result

