var findKOr = function(nums, k) {
    let result = 0;
    for (let b = 0; b < 32; b++) {
        let cnt = 0;
        for (const x of nums) {
            if ((x >>> b) & 1) cnt++;
        }
        if (cnt >= k) {
            result |= (1 << b);
        }
    }
    return result >>> 0;
};
